module Slice(
  input         clock,
                reset,
  output        io_in_ready,
  input         io_in_valid,
  input  [31:0] io_in_bits,
  input         io_out_ready,
  output        io_out_valid,
  output [31:0] io_out_bits
);

  reg  [1:0]  ipos;
  reg  [1:0]  opos;
  reg  [31:0] mem_0;
  reg  [31:0] mem_1;
  wire        full = ipos[0] == opos[0] & ipos[1] != opos[1];
  wire        io_out_valid_0 = ipos != opos;
  wire        ivalid = io_in_valid & ~full;
  wire        ovalid = io_out_valid_0 & io_out_ready;
  wire        _GEN = ivalid & ~ovalid;
  wire        _GEN_0 = ivalid & ovalid;
  always @(posedge clock or posedge reset) begin
    if (reset) begin
      ipos <= 2'h0;
      opos <= 2'h0;
      mem_0 <= 32'h0;
      mem_1 <= 32'h0;
    end
    else begin
      if (ivalid)
        ipos <= ipos + 2'h1;
      if (ovalid)
        opos <= opos + 2'h1;
      if (ovalid & full)
        mem_0 <= mem_1;
      else if (_GEN & ipos == opos | _GEN_0)
        mem_0 <= io_in_bits;
      if (_GEN & io_out_valid_0 | _GEN_0 & full)
        mem_1 <= io_in_bits;
    end
  end // always @(posedge, posedge)
  `ifdef ENABLE_INITIAL_REG_
    `ifdef FIRRTL_BEFORE_INITIAL
      `FIRRTL_BEFORE_INITIAL
    `endif // FIRRTL_BEFORE_INITIAL
    logic [31:0] _RANDOM[0:2];
    initial begin
      `ifdef INIT_RANDOM_PROLOG_
        `INIT_RANDOM_PROLOG_
      `endif // INIT_RANDOM_PROLOG_
      `ifdef RANDOMIZE_REG_INIT
        for (logic [1:0] i = 2'h0; i < 2'h3; i += 2'h1) begin
          _RANDOM[i] = `RANDOM;
        end
        ipos = _RANDOM[2'h0][1:0];
        opos = _RANDOM[2'h0][3:2];
        mem_0 = {_RANDOM[2'h0][31:6], _RANDOM[2'h1][5:0]};
        mem_1 = {_RANDOM[2'h1][31:6], _RANDOM[2'h2][5:0]};
      `endif // RANDOMIZE_REG_INIT
      if (reset) begin
        ipos = 2'h0;
        opos = 2'h0;
        mem_0 = 32'h0;
        mem_1 = 32'h0;
      end
    end // initial
    `ifdef FIRRTL_AFTER_INITIAL
      `FIRRTL_AFTER_INITIAL
    `endif // FIRRTL_AFTER_INITIAL
  `endif // ENABLE_INITIAL_REG_
  assign io_in_ready = ~full;
  assign io_out_valid = io_out_valid_0;
  assign io_out_bits = mem_0;
endmodule

