          : io_in_2_valid ? io_in_2_bits_addr : io_in_3_bits_addr;
  assign io_out_bits_op =
    io_in_0_valid
      ? io_in_0_bits_op
      : io_in_1_valid
          ? io_in_1_bits_op
          : io_in_2_valid ? io_in_2_bits_op : io_in_3_bits_op;
